practice_tasks.solution:
def to_int(value, fallback):
    try:
        return int(value)
    except ValueError:
        return fallback

print(to_int('42', 0))
print(to_int('abc', 0))

challenge.solution:
def parse_port(raw):
    if raw is None:
        return 8000
    try:
        return int(raw)
    except ValueError:
        return 8000

print(parse_port('5432'))
print(parse_port('abc'))
print(parse_port(None))
